insert into public.recipes (id, name, ingredients, time_minutes, calories, difficulty, diet, tags, category, steps, image_url, source, external_id)
select
  (select coalesce(max(id), 0) from public.recipes) + row_number() over (order by n.name),
  n.name, n.ingredients, n.time_minutes, n.calories, n.difficulty, n.diet, n.tags, n.category, n.steps,
  '', 'csv', ''
from new_recipes n
where not exists (select 1 from public.recipes r where lower(r.name) = lower(n.name));
